442:     private void createNewTasks(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
443:                                 final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate) {
444:         final Collection<Task> newActiveTasks = activeTaskCreator.createTasks(mainConsumer, activeTasksToCreate);
445:         final Collection<Task> newStandbyTasks = standbyTaskCreator.createTasks(standbyTasksToCreate);
446: 
447:         if (stateUpdater == null) {
448:             tasks.addActiveTasks(newActiveTasks);
449:             tasks.addStandbyTasks(newStandbyTasks);
450:         } else {
451:             tasks.addPendingTasksToInit(newActiveTasks);
452:             tasks.addPendingTasksToInit(newStandbyTasks);
453:         }
454:     }
