456:     private void handleTasksWithoutStateUpdater(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
457:                                                 final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
458:                                                 final Map<Task, Set<TopicPartition>> tasksToRecycle,
459:                                                 final Set<Task> tasksToCloseClean) {
460:         for (final Task task : tasks.allTasks()) {
461:             final TaskId taskId = task.id();
462:             if (activeTasksToCreate.containsKey(taskId)) {
463:                 if (task.isActive()) {
464:                     final Set<TopicPartition> topicPartitions = activeTasksToCreate.get(taskId);
465:                     if (tasks.updateActiveTaskInputPartitions(task, topicPartitions)) {
466:                         task.updateInputPartitions(topicPartitions, topologyMetadata.nodeToSourceTopics(task.id()));
467:                     }
468:                     task.resume();
469:                 } else {
470:                     tasksToRecycle.put(task, activeTasksToCreate.get(taskId));
471:                 }
472:                 activeTasksToCreate.remove(taskId);
473:             } else if (standbyTasksToCreate.containsKey(taskId)) {
474:                 if (!task.isActive()) {
475:                     updateInputPartitionsOfStandbyTaskIfTheyChanged(task, standbyTasksToCreate.get(taskId));
476:                     task.resume();
477:                 } else {
478:                     tasksToRecycle.put(task, standbyTasksToCreate.get(taskId));
479:                 }
480:                 standbyTasksToCreate.remove(taskId);
481:             } else {
482:                 tasksToCloseClean.add(task);
483:             }
484:         }
485:     }
486: 
487:     private void updateInputPartitionsOfStandbyTaskIfTheyChanged(final Task task,
488:                                                                  final Set<TopicPartition> inputPartitions) {
489:         /*
490:         We should only update input partitions of a standby task if the input partitions really changed. Updating the
491:         input partitions of tasks also updates the mapping from source nodes to input topics in the processor topology
492:         within the task. The mapping is updated with the topics from the topology metadata. The topology metadata does
493:         not prefix intermediate internal topics with the application ID. Thus, if a standby task has input partitions
494:         from an intermediate internal topic the update of the mapping in the processor topology leads to an invalid
495:         topology exception during recycling of a standby task to an active task when the input queues are created. This
496:         is because the input topics in the processor topology and the input partitions of the task do not match because
497:         the former miss the application ID prefix.
498:         For standby task that have only input partitions from intermediate internal topics this check avoids the invalid
499:         topology exception. Unfortunately, a subtopology might have input partitions subscribed to with a regex
500:         additionally intermediate internal topics which might still lead to an invalid topology exception during recycling
501:         irrespectively of this check here. Thus, there is still a bug to fix here.
502:          */
503:         if (!task.inputPartitions().equals(inputPartitions)) {
504:             task.updateInputPartitions(inputPartitions, topologyMetadata.nodeToSourceTopics(task.id()));
505:         }
506:     }
