508:     private void handleTasksWithStateUpdater(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
509:                                              final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
510:                                              final Map<Task, Set<TopicPartition>> tasksToRecycle,
511:                                              final Set<Task> tasksToCloseClean,
512:                                              final Map<TaskId, RuntimeException> failedTasks) {
513:         handleTasksPendingInitialization();
514:         handleRestoringAndUpdatingTasks(activeTasksToCreate, standbyTasksToCreate, failedTasks);
515:         handleRunningAndSuspendedTasks(activeTasksToCreate, standbyTasksToCreate, tasksToRecycle, tasksToCloseClean);
516:     }
