518:     private void handleTasksPendingInitialization() {
519:         // All tasks pending initialization are not part of the usual bookkeeping
520: 
521:         final Set<Task> tasksToCloseDirty = new HashSet<>();
522: 
523:         for (final Task task : tasks.drainPendingTasksToInit()) {
524:             closeTaskClean(task, tasksToCloseDirty, new HashMap<>());
525:         }
526:         for (final Task task : tasksToCloseDirty) {
527:             closeTaskDirty(task, false);
528:         }
529:     }
