531:     private void handleRunningAndSuspendedTasks(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
532:                                                 final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
533:                                                 final Map<Task, Set<TopicPartition>> tasksToRecycle,
534:                                                 final Set<Task> tasksToCloseClean) {
535:         for (final Task task : tasks.allNonFailedTasks()) {
536:             if (!task.isActive()) {
537:                 throw new IllegalStateException("Standby tasks should only be managed by the state updater, " +
538:                     "but standby task " + task.id() + " is managed by the stream thread");
539:             }
540:             final TaskId taskId = task.id();
541:             if (activeTasksToCreate.containsKey(taskId)) {
542:                 handleReassignedActiveTask(task, activeTasksToCreate.get(taskId));
543:                 activeTasksToCreate.remove(taskId);
544:             } else if (standbyTasksToCreate.containsKey(taskId)) {
545:                 tasksToRecycle.put(task, standbyTasksToCreate.get(taskId));
546:                 standbyTasksToCreate.remove(taskId);
547:             } else {
548:                 tasksToCloseClean.add(task);
549:             }
550:         }
